const { Stream } = require('@most/types');
const { newStream, continueWith, endWith, periodic } = require('@most/core');
const { runEffects } = require('@most/core');

// Create a Stream from an array
const createStreamFromArray = (array) => {
  return newStream((add, end) => {
    array.forEach(x => add(x));
    end();
  });
};

// Transform each element in the Stream with an effectful function
const transformStreamElements = (stream, effectfulFunction) => {
  return stream.map(effectfulFunction);
};

// Collect all results into an array
const collectStreamIntoArray = (stream) => {
  return runEffects(stream.observe(continueWith(endWith([]))));
};

// Chain the three functions together
const chainFunctions = (array, effectfulFunction) => {
  const stream = createStreamFromArray(array);
  const transformedStream = transformStreamElements(stream, effectfulFunction);
  return collectStreamIntoArray(transformedStream);
};
```

